package main

import "fmt"

func main() {
    var count, valor, pares int
    fmt.Scan(&count)

    // A Chave será o NÚMERO e o Valor será a QUANTIDADE de vezes que apareceu
    estoque := make(map[int]int)

    for i := 0; i < count; i++ {
        fmt.Scan(&valor)

        // Verificamos se o negativo desse valor já está no "estoque"
        if estoque[-valor] > 0 {
            pares++            // Encontramos um par!
            estoque[-valor]--  // Removemos um do estoque para não usar o mesmo número de novo
        } else {
            // Se não tem o par, guardamos esse número para ver se o par dele aparece depois
            estoque[valor]++
        }
    }

    fmt.Println(pares)
}
